// src/pages/ToursPage.jsx (UPDATED)
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './ToursPage.css';

const ToursPage = () => {
  const navigate = useNavigate();
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchTours();
  }, []);

  const fetchTours = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/tours');
      const data = await response.json();

      if (data.status === 'success') {
        setTours(data.data);
      } else {
        setError('Failed to load tours');
      }
    } catch (err) {
      console.error('Error fetching tours:', err);
      setError('Failed to connect to server');
    } finally {
      setLoading(false);
    }
  };

  const handleSelectTour = (tour) => {
    const days = parseInt(tour.duration.split(' ')[0]);

    // Store tour selection with MongoDB ID
    const tourSelection = {
      id: tour._id,  // Use MongoDB _id instead of numeric id
      name: tour.name,
      duration: days,
      pricePerDay: 80, // You might want to calculate this from tour.price / days
      basePrice: tour.price,
      groupSize: tour.groupSize,
      features: tour.features
    };

    localStorage.setItem('selectedTour', JSON.stringify(tourSelection));

    // Navigate to tour guides page with MongoDB ID
    navigate(`/tour-guides?tour=${tour._id}&name=${encodeURIComponent(tour.name)}&duration=${days}&pricePerDay=80`);
  };

  if (loading) {
    return (
      <div className="tours-page">
        <div className="container">
          <div className="loading-spinner"></div>
          <p>Loading tours...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="tours-page">
        <div className="container">
          <div className="error-message">
            ❌ {error}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="tours-page">
      {/* Hero Section */}
      <section className="tours-hero">
        <div className="container">
          <div className="hero-content">
            <h1 className="hero-title">Our Tour Packages</h1>
            <p className="hero-subtitle">
              Carefully curated experiences to showcase the best of Sri Lanka
            </p>
          </div>
        </div>
      </section>

      {/* Tours Grid */}
      <section className="tours-section">
        <div className="container">
          <div className="tours-grid">
            {tours.map((tour) => {
              const days = parseInt(tour.duration.split(' ')[0]);

              return (
                <div key={tour._id} className="tour-card">
                  <div className="tour-image">
                    <img src={tour.image} alt={tour.name} className="tour-img" />
                  </div>
                  <div className="tour-content">
                    <h3 className="tour-name">{tour.name}</h3>
                    <p className="tour-description">{tour.description}</p>

                    <div className="tour-details">
                      <div className="detail">
                        <span className="detail-label">Duration:</span>
                        <span className="detail-value">{tour.duration}</span>
                      </div>
                      <div className="detail">
                        <span className="detail-label">Group Size:</span>
                        <span className="detail-value">{tour.groupSize}</span>
                      </div>
                      <div className="detail">
                        <span className="detail-label">From:</span>
                        <span className="detail-value">${tour.price}/person</span>
                      </div>
                    </div>

                    <div className="tour-features">
                      {tour.features.map((feature, index) => (
                        <span key={index} className="feature-tag">{feature}</span>
                      ))}
                    </div>

                    <div className="tour-actions">
                      <button 
                        onClick={() => handleSelectTour(tour)}
                        className="btn-primary"
                      >
                        Select This Tour
                      </button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </section>
    </div>
  );
};

export default ToursPage;
